import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'

describe('GET /api/health', () => {
  beforeEach(() => {
    vi.useFakeTimers()
  })

  afterEach(() => {
    vi.useRealTimers()
    vi.resetModules()
  })

  it('returns 200 status', async () => {
    const { GET } = await loadHandler()
    const response = await GET({ request: new Request('http://localhost/api/health') })
    expect(response.status).toBe(200)
  })

  it('returns { status: "ok" } in body', async () => {
    const { GET } = await loadHandler()
    const response = await GET({ request: new Request('http://localhost/api/health') })
    const body = await response.json()
    expect(body.status).toBe('ok')
  })

  it('returns a valid ISO 8601 timestamp', async () => {
    vi.setSystemTime(new Date('2026-04-05T12:00:00.000Z'))
    const { GET } = await loadHandler()
    const response = await GET({ request: new Request('http://localhost/api/health') })
    const body = await response.json()
    expect(body.timestamp).toBe('2026-04-05T12:00:00.000Z')
  })

  it('returns uptime_seconds as a non-negative integer', async () => {
    vi.setSystemTime(new Date('2026-04-05T12:00:00.000Z'))
    const { GET } = await loadHandler()

    // Advance time by 5 seconds
    vi.setSystemTime(new Date('2026-04-05T12:00:05.000Z'))

    const response = await GET({ request: new Request('http://localhost/api/health') })
    const body = await response.json()
    expect(body.uptime_seconds).toBe(5)
    expect(Number.isInteger(body.uptime_seconds)).toBe(true)
  })

  it('returns Content-Type application/json', async () => {
    const { GET } = await loadHandler()
    const response = await GET({ request: new Request('http://localhost/api/health') })
    expect(response.headers.get('Content-Type')).toBe('application/json')
  })
})

/**
 * Dynamically import the handler so each test gets a fresh module
 * (important for uptime_seconds which depends on module-level startTime).
 */
async function loadHandler() {
  const mod = await vi.importActual<typeof import('./health')>('./health')
  // The handler functions are nested inside APIRoute
  const route = mod.APIRoute as any
  // TanStack Start APIRoute has methods like GET directly or via options
  // We access the GET handler from the route definition
  return { GET: route.methods.GET ?? route.GET }
}

