import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'

describe('getHealthStatus', () => {
  beforeEach(() => {
    vi.useFakeTimers()
  })

  afterEach(() => {
    vi.useRealTimers()
    vi.resetModules()
  })

  it('returns status "ok"', async () => {
    const { getHealthStatus } = await vi.importActual<
      typeof import('./health')
    >('./health')
    const result = getHealthStatus()
    expect(result.status).toBe('ok')
  })

  it('returns a valid ISO 8601 timestamp', async () => {
    vi.setSystemTime(new Date('2026-04-05T12:00:00.000Z'))
    const { getHealthStatus } = await vi.importActual<
      typeof import('./health')
    >('./health')
    const result = getHealthStatus()
    expect(result.timestamp).toBe('2026-04-05T12:00:00.000Z')
  })

  it('returns uptime_seconds as a non-negative integer', async () => {
    vi.setSystemTime(new Date('2026-04-05T12:00:00.000Z'))
    const { getHealthStatus } = await vi.importActual<
      typeof import('./health')
    >('./health')

    // Advance time by 5 seconds
    vi.setSystemTime(new Date('2026-04-05T12:00:05.000Z'))

    const result = getHealthStatus()
    expect(result.uptime_seconds).toBe(5)
    expect(Number.isInteger(result.uptime_seconds)).toBe(true)
  })

  it('returns uptime_seconds of 0 when called immediately', async () => {
    vi.setSystemTime(new Date('2026-04-05T12:00:00.000Z'))
    const { getHealthStatus } = await vi.importActual<
      typeof import('./health')
    >('./health')
    const result = getHealthStatus()
    expect(result.uptime_seconds).toBe(0)
  })

  it('floors partial seconds in uptime', async () => {
    vi.setSystemTime(new Date('2026-04-05T12:00:00.000Z'))
    const { getHealthStatus } = await vi.importActual<
      typeof import('./health')
    >('./health')

    // Advance 2.9 seconds — should floor to 2
    vi.setSystemTime(new Date('2026-04-05T12:00:02.900Z'))
    const result = getHealthStatus()
    expect(result.uptime_seconds).toBe(2)
  })
})

